import{_ as a,C as r,o as i,c as n,E as d,w as s,a as o,a0 as l}from"./chunks/framework.CkNTPv-z.js";const g=JSON.parse('{"title":"Finland Healthcare & HRT","description":"Transgender healthcare access in Finland","frontmatter":{"layout":"doc","title":"Finland Healthcare & HRT","description":"Transgender healthcare access in Finland"},"headers":[],"relativePath":"europe/finland/healthcare.md","filePath":"europe/finland/healthcare.md","lastUpdated":null}'),c={name:"europe/finland/healthcare.md"};function h(p,t,u,m,y,f){const e=r("Badge");return i(),n("div",null,[d(e,{variant:"yellow"},{default:s(()=>[...t[0]||(t[0]=[o("Gatekeeping (Improving)",-1)])]),_:1}),t[1]||(t[1]=l('<h1 id="healthcare-hrt-in-finland" tabindex="-1">Healthcare &amp; HRT in Finland <a class="header-anchor" href="#healthcare-hrt-in-finland" aria-label="Permalink to &quot;Healthcare &amp; HRT in Finland&quot;">​</a></h1><h2 id="access-model" tabindex="-1">Access Model <a class="header-anchor" href="#access-model" aria-label="Permalink to &quot;Access Model&quot;">​</a></h2><p>Finland has historically followed a gatekeeping model for transgender healthcare, requiring a psychiatric diagnosis of gender dysphoria before accessing HRT. The system is in transition following the 2023 self-ID law, but clinical practice has been slower to change. Access is centralised through five university hospital gender clinics.</p><p>The typical pathway involves: GP referral → psychiatric evaluation (6-12 month wait) → diagnosis → endocrinology referral → HRT. Total wait time from first appointment to HRT can be 1-2 years.</p><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>HUS Gender Clinic</td><td>Helsinki</td><td>Transdiagnostic assessment, HRT, surgery referrals</td></tr><tr><td>TAYS Gender Clinic</td><td>Tampere</td><td>Gender identity evaluation, HRT</td></tr><tr><td>TYKS Gender Clinic</td><td>Turku</td><td>Assessment, HRT, counselling</td></tr><tr><td>OYS Gender Clinic</td><td>Oulu</td><td>Gender services, HRT</td></tr><tr><td>KYS Gender Clinic</td><td>Kuopio</td><td>Gender identity services</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>Finland recognises EU/EEA prescriptions. Non-EU arrivals must see a Finnish doctor to obtain local prescriptions. A translated medical history (in Finnish, Swedish, or English) documenting your HRT is strongly recommended.</p><p>Carry up to a 3-month supply of HRT for personal use with a valid prescription from your home country.</p><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender-affirming surgeries are available at HUS (Helsinki) and are publicly funded for residents. Top surgery, bottom surgery, hysterectomy, and facial feminisation are available. Wait times for surgery are typically 12-24 months. Some patients choose private surgery abroad (e.g., Thailand, Germany).</p><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public Cost</th><th>Private Cost</th></tr></thead><tbody><tr><td>GP visit</td><td>€15-30</td><td>€100-200</td></tr><tr><td>Psychiatric assessment</td><td>€30-50 (public)</td><td>€200-400</td></tr><tr><td>HRT (monthly)</td><td>€15-40</td><td>€50-100</td></tr><tr><td>Top Surgery</td><td>Covered (public)</td><td>€5,000-10,000</td></tr><tr><td>Bottom Surgery</td><td>Covered (public)</td><td>€15,000-30,000</td></tr></tbody></table>',13))])}const T=a(c,[["render",h]]);export{g as __pageData,T as default};
